const topic = msg.topic || '';
let line;
if (topic.endsWith('/ppm')) {
    const p = msg.payload;
    const raw = Number(p.raw);
    const idx = Number(p.gas_index);
    const ppm = Number(p.ppm); // compatibilidad con payload antiguo
    const gasIndex = Number.isNaN(idx) ? (Number.isNaN(ppm) ? NaN : ppm) : idx;
    if (Number.isNaN(gasIndex)) return null;
    const safeRaw = Number.isNaN(raw) ? -1 : raw;
    const sens = String(p.sensor || 'MQ-2').replace(/[ ,=]/g, '_');
    line = `gas,sensor=${sens} gas_index=${gasIndex},raw=${safeRaw}`;
} else if (topic.endsWith('/alerta')) {
    const p = msg.payload;
    const idx = Number(p.gas_index);
    const ppm = Number(p.ppm);
    const gasIndex = Number.isNaN(idx) ? (Number.isNaN(ppm) ? NaN : ppm) : idx;
    if (Number.isNaN(gasIndex)) return null;
    const lvl = String(p.level || 'CRITICAL').split(String.fromCharCode(34)).join('');
    const sens2 = String(p.sensor || 'MQ-2').replace(/[ ,=]/g, '_');
    line = `gas_alert,sensor=${sens2} gas_index=${gasIndex},level="${lvl}"`;
} else {
    return null;
}
msg.method = 'POST';
msg.url = 'http://influxdb:8086/api/v2/write?org=iot_gas&bucket=gas_readings&precision=s';
msg.headers = {
    Authorization: 'Token my-super-secret-token-iot-gas',
    'Content-Type': 'text/plain; charset=utf-8'
};
msg.payload = line;
return msg;
